{
var size = context.TileSize;
var brushSize = Math.Max(1, GetInt(parameters, "brushSize", 4));
var hardness = Math.Clamp(GetFloat(parameters, "hardness", 1f), 0f, 1f);

// Use Color port (inputs[1]) if connected, fall back to parameter
var r = 1f; var g = 1f; var b = 1f;
if (inputs.Length > 1 && inputs[1] != null)
{
    // Read color from the center of the color buffer
    var (cr, cg, cb, _) = inputs[1].GetPixel(inputs[1].Width / 2, inputs[1].Height / 2);
    r = cr; g = cg; b = cb;
}
else
{
    var color = GetColor(parameters, "color", Colors.White);
    r = color.R / 255f;
    g = color.G / 255f;
    b = color.B / 255f;
}

// Use Float position port (inputs[0]) if connected, else center
var cx = size / 2;
var cy = size / 2;
if (inputs.Length > 0 && inputs[0] != null)
{
    // Read first pixel value as position
    var (px, py, _, _) = inputs[0].GetPixel(0, 0);
    cx = Math.Clamp((int)(px * size), 0, size - 1);
    cy = Math.Clamp((int)(py * size), 0, size - 1);
}

var buffer = PixelBufferPool.Borrow(size, size);
var halfBrush = brushSize * 0.5f;
var radius = halfBrush;
var innerRadius = radius * Math.Max(0.001f, hardness);

buffer.ParallelForEachPixel((x, y) =>
{
    var dx = x - cx;
    var dy = y - cy;
    var dist = MathF.Sqrt(dx * dx + dy * dy);

    float alpha;
    if (dist >= radius)
    {
        alpha = 0f;
    }
    else if (dist <= innerRadius)
    {
        alpha = 1f;
    }
    else
    {
        // Smooth falloff between inner and outer radius
        var t = (dist - innerRadius) / (radius - innerRadius + 0.0001f);
        alpha = 1f - (t * t * (3f - 2f * t));
    }

    buffer.SetPixel(x, y, r, g, b, alpha);
});

return buffer;
}
